content.content:
// tableHeader: texto que abarca todas las columnas como título de la tabla
{
  "config": {
    "source": "miPlugin|mock/data.json",
    "tableHeader": "Directorio de usuarios activos",
    "columns": [
      { "id":   { "name": "#",      "width": "55px", "align": "center" } },
      { "name": { "name": "Nombre", "width": "180px" } }
    ]
  }
}

// tableFooter: texto en el <tfoot> que abarca todas las columnas
{
  "config": {
    "source": "miPlugin|mock/data.json",
    "tableFooter": "Total: 5 usuarios registrados",
    "columns": [
      { "id":   { "name": "#",      "width": "55px", "align": "center" } },
      { "name": { "name": "Nombre", "width": "180px" } }
    ]
  }
}

// tableHeader + tableFooter: título arriba y resumen abajo
{
  "config": {
    "source": "miPlugin|mock/data.json",
    "tableHeader": "Directorio de usuarios activos",
    "tableFooter": "Total: 5 usuarios — Última actualización: hoy",
    "columns": [
      { "id":   { "name": "#",      "width": "55px", "align": "center" } },
      { "name": { "name": "Nombre", "width": "180px" } }
    ]
  }
}
